import type { LanguagePreference } from '@/lib/strapi';

export const DEFAULT_LANGUAGE: LanguagePreference = 'pt-BR';
export const SUPPORTED_LANGUAGES: LanguagePreference[] = [
  'pt-BR',
  'en',
  'es',
  'fr',
];

export const USER_PREFERENCES_UPDATED_EVENT = 'user-preferences-updated';
export const APP_SETTINGS_UPDATED_EVENT = 'app-settings-updated';

export function normalizeLanguage(value?: string | null): LanguagePreference {
  if (value && SUPPORTED_LANGUAGES.includes(value as LanguagePreference)) {
    return value as LanguagePreference;
  }

  return DEFAULT_LANGUAGE;
}

